+import type { Adapter } from "../adapter";
+import type { ToolDefinition, ToolResult } from "../../models/provider";
+import type { EvidenceLogger } from "../../evidence/logger";
+
+const KEY_MAP: Record<string, string> = {
+  Enter: "Enter",
+  Tab: "Tab",
+  Escape: "Escape",
+  Up: "Up",
+  Down: "Down",
+  Left: "Left",
+  Right: "Right",
+  Backspace: "BSpace",
+  Delete: "DC",
+  Home: "Home",
+  End: "End",
+  PageUp: "PageUp",
+  PageDown: "PageDown",
+  "Ctrl+C": "C-c",
+  "Ctrl+D": "C-d",
+  "Ctrl+Z": "C-z",
+  "Ctrl+X": "C-x",
+  "Ctrl+O": "C-o",
+  "Ctrl+S": "C-s",
+  "Ctrl+W": "C-w",
+  "Ctrl+K": "C-k",
+  "Ctrl+G": "C-g",
+};
+
+const AVAILABLE_KEYS = Object.keys(KEY_MAP).join(", ");
+
+export class TUIAdapter implements Adapter {
+  private _sessionName: string | null = null;
+
+  get sessionName(): string {
+    if (!this._sessionName) throw new Error("Session not started");
+    return this._sessionName;
+  }
+
+  async start(command: string): Promise<void> {
+    const id = `vet-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
+    this._sessionName = id;
+
+    const result = Bun.spawnSync([
+      "tmux",
+      "new-session",
+      "-d",
+      "-s",
+      id,
+      "-x",
+      "120",
+      "-y",
+      "40",
+      command,
+    ]);
+
+    if (result.exitCode !== 0) {
+      const stderr = new TextDecoder().decode(result.stderr);
+      throw new Error(`Failed to start tmux session: ${stderr}`);
+    }
+  }
+
+  async readScreen(): Promise<string> {
+    const result = Bun.spawnSync([
+      "tmux",
+      "capture-pane",
+      "-t",
+      this.sessionName,
+      "-p",
+    ]);
+
+    if (result.exitCode !== 0) {
+      const stderr = new TextDecoder().decode(result.stderr);
+      throw new Error(`Failed to capture pane: ${stderr}`);
+    }
+
+    return new TextDecoder().decode(result.stdout);
+  }
+
+  async type(text: string): Promise<void> {
+    const result = Bun.spawnSync([
+      "tmux",
+      "send-keys",
+      "-t",
+      this.sessionName,
+      "-l",
+      text,
+    ]);
+
+    if (result.exitCode !== 0) {
+      const stderr = new TextDecoder().decode(result.stderr);
+      throw new Error(`Failed to send keys: ${stderr}`);
+    }
+  }
+
+  async press(key: string): Promise<void> {
+    const mapped = KEY_MAP[key];
+    if (!mapped) throw new Error(`Unknown key: ${key}. Available: ${AVAILABLE_KEYS}`);
+
+    const result = Bun.spawnSync([
+      "tmux",
+      "send-keys",
+      "-t",
+      this.sessionName,
+      mapped,
+    ]);
+
+    if (result.exitCode !== 0) {
+      const stderr = new TextDecoder().decode(result.stderr);
+      throw new Error(`Failed to send key: ${stderr}`);
+    }
+  }
+
+  async close(): Promise<void> {
+    if (!this._sessionName) return;
+
+    const result = Bun.spawnSync([
+      "tmux",
+      "kill-session",
+      "-t",
+      this._sessionName,
+    ]);
+
+    if (result.exitCode !== 0) {
+      const stderr = new TextDecoder().decode(result.stderr);
+      throw new Error(`Failed to kill session: ${stderr}`);
+    }
+
+    this._sessionName = null;
+  }
+
+  toolDefinitions(): ToolDefinition[] {
+    return [
+      {
+        name: "type",
+        description: "Type literal text into the terminal",
+        parameters: {
+          type: "object",
+          properties: {
+            text: { type: "string", description: "Text to type" },
+          },
+          required: ["text"],
+        },
+      },
+      {
+        name: "press",
+        description: `Press a special key. Available keys: ${AVAILABLE_KEYS}`,
+        parameters: {
+          type: "object",
+          properties: {
+            key: { type: "string", description: "Key name to press" },
+          },
+          required: ["key"],
+        },
+      },
+      {
+        name: "read_screen",
+        description: "Read the current terminal screen contents",
+        parameters: {
+          type: "object",
+          properties: {},
+        },
+      },
+    ];
+  }
+
+  async executeTool(
+    name: string,
+    args: Record<string, unknown>,
+    logger: EvidenceLogger
+  ): Promise<ToolResult> {
+    logger.logAction(name, args);
+
+    switch (name) {
+      case "type": {
+        await this.type(args.text as string);
+        return { text: "typed" };
+      }
+      case "press": {
+        await this.press(args.key as string);
+        return { text: "pressed" };
+      }
+      case "read_screen": {
+        const screen = await this.readScreen();
+        return { text: screen };
+      }
+      default:
+        throw new Error(`Unknown tool: ${name}`);
+    }
+  }
+}

